mapper.select:
WITH expanded AS ( SELECT TRIM(t.target) AS target, c.global_highest_phase_score AS score, c.global_highest_phase AS phase_name, c.drug_id FROM ci_tracking_latest c CROSS JOIN LATERAL unnest(c.targets) AS t(target) WHERE c.disease_id IN
#{id}
AND c.indication_top_global_latest_stage IN
#{p}
), base AS ( SELECT LEAST(a.target, b.target) AS target_a, GREATEST(a.target, b.target) AS target_b, a.score, a.phase_name, a.drug_id FROM expanded a JOIN expanded b ON a.drug_id = b.drug_id AND a.target < b.target ), agg AS ( SELECT target_a, target_b, MAX(score) AS max_score, COUNT(DISTINCT drug_id) AS drug_count FROM base GROUP BY target_a, target_b ), result AS ( SELECT DISTINCT ON (a.target_a, a.target_b) a.target_a, a.target_b, a.max_score AS score, a.drug_count, b.phase_name FROM agg a JOIN base b ON b.target_a = a.target_a AND b.target_b = a.target_b AND b.score = a.max_score ORDER BY a.target_a, a.target_b, b.phase_name ) SELECT * FROM result ORDER BY target_a, target_b

SELECT TRIM(t.target) AS target, MAX(c.global_highest_phase_score) AS max_score FROM ci_tracking_latest c CROSS JOIN LATERAL unnest(c.targets) AS t(target) WHERE c.disease_id IN
#{id}
AND c.indication_top_global_latest_stage IN
#{p}
GROUP BY TRIM(t.target) ORDER BY MAX(c.global_highest_phase_score) DESC, TRIM(t.target)

SELECT DISTINCT c.drug_name_en AS drug_name_en, c.originator AS originator, c.research_institute AS research_institute, c.indication_top_global_latest_stage AS highest_phase, c.global_highest_phase_score AS highest_phase_score, TO_CHAR(c.indication_top_global_start_date, 'YYYY-MM-DD') AS highest_phase_date, c.nct_id AS nct_id, c.moa AS moa FROM ci_tracking_latest c WHERE c.disease_id IN
#{id}
AND c.targets @> ARRAY[#{target}, #{pairTarget}]::text[] AND c.indication_top_global_latest_stage IN
#{p}
ORDER BY highest_phase_score DESC LIMIT 20

SELECT c.drug_name_en AS drug_name_en, c.drug_name_cn AS drug_name_cn, c.targets_raw AS targets_raw, c.indication_top_global_latest_stage AS phase, c.global_highest_phase_score AS phase_score, c.originator AS originator, c.research_institute AS research_institute, TO_CHAR(c.indication_top_global_start_date, 'YYYY-MM-DD') AS phase_date, c.nct_id AS nct_id, c.harbour_indication_name AS disease_name, c.ta AS ta_name, CASE WHEN array_length(c.targets, 1) > 1 THEN '是' ELSE '否' END AS is_combo FROM ci_tracking_latest c WHERE c.disease_id IN
#{id}
AND c.indication_top_global_latest_stage IN
#{p}
ORDER BY c.global_highest_phase_score DESC, c.drug_name_en
